import { inject, Injectable } from '@angular/core';
import {
  AXValidationRuleResult,
  AXValidationService,
  AXValidationSummary,
} from '@acorex/core/validation';

@Injectable({ providedIn: 'root' })
export class FieldValidatorService {
  private validation = inject(AXValidationService);

  // aliasهای config مثل email و phone به rule زیرین خود resolve می‌شوند.
  validateEmail(value: string): Promise<AXValidationRuleResult> {
    return this.validation.validate('email', value);
  }

  // rule built-in همراه با کلید ترجمه برای message.
  validateRequired(value: unknown, title: string): Promise<AXValidationRuleResult> {
    return this.validation.validate('required', value, {
      title,
      message: '@acorex:validation.messages.required',
    });
  }

  // اجرای چند rule روی یک مقدار.
  validatePassword(value: string): Promise<AXValidationSummary> {
    return this.validation
      .ruleFor(value)
      .addRule('required', { title: 'Password' })
      .addRule('minLength', { value: 8 })
      .validate();
  }

  // برای منطق business اختصاصی از callback استفاده کنید.
  validateUsername(value: string): Promise<AXValidationRuleResult> {
    return this.validation.validate('callback', value, {
      validate: (currentValue: string) =>
        /^[a-zA-Z0-9_]{3,20}$/.test(currentValue)
          ? { result: true }
          : { result: false, message: 'Invalid username' },
    });
  }
}

import { ApplicationConfig, importProvidersFrom } from '@angular/core';
import {
  AXValidationModule,
  AX_VALIDATION_CONFIG,
  validationConfig,
} from '@acorex/core/validation';

export const appConfig: ApplicationConfig = {
  providers: [
    importProvidersFrom(AXValidationModule.forRoot()),
    // Optional: extend named aliases
    {
      provide: AX_VALIDATION_CONFIG,
      useValue: validationConfig({
        rules: {
          username: {
            rule: 'regex',
            options: {
              pattern: /^[a-zA-Z0-9_]{3,20}$/,
              message: '@acorex:validation.messages.username',
            },
          },
        },
      }),
    },
  ],
};

import { inject, Injectable } from '@angular/core';
import { AXValidationService } from '@acorex/core/validation';

@Injectable({ providedIn: 'root' })
export class ValidateService {
  private validation = inject(AXValidationService);

  async checkEmail(email: string) {
    // Uses email alias from AX_VALIDATION_CONFIG
    return this.validation.validate('email', email);
  }

  async checkRequired(value: unknown, fieldTitle: string) {
    return this.validation.validate('required', value, {
      title: fieldTitle,
      message: '@acorex:validation.messages.required',
    });
  }

  async checkAge(age: number) {
    return this.validation.validate('greaterThan', age, {
      value: 18,
      inclusive: true,
      message: 'You must be at least 18 years old.',
    });
  }
}

import { inject } from '@angular/core';
import { AXValidationService } from '@acorex/core/validation';

async function validatePassword(password: string) {
  const validation = inject(AXValidationService);

  const summary = await validation
    .ruleFor(password)
    .addRule('required')
    .addRule('minLength', { value: 8 })
    .addRule('maxLength', { value: 64 })
    .addRule('regex', {
      pattern: /[A-Z]/,
      message: 'Must contain an uppercase letter.',
    })
    .validate();

  if (!summary.result) {
    const firstError = summary.rules.find(r => !r.result);
    console.error(firstError?.message);
  }

  return summary;
}

import { inject } from '@angular/core';
import { AXValidationService } from '@acorex/core/validation';

function validateContent(val: string) {
  if (!val?.trim()) {
    return { result: false, message: 'Content cannot be empty' };
  }
  if (val.trim().length < 10) {
    return { result: false, message: 'At least 10 characters required' };
  }
  return { result: true };
}

async function validateEditorContent(content: string) {
  const validation = inject(AXValidationService);

  return validation.validate('callback', content, {
    validate: validateContent,
  });
}

