import { Injectable } from '@angular/core';
import { AXValidationRule, AXValidationRuleOptions, AXValidationRuleResult } from '@acorex/core/validation';

export interface AXNationalIdRuleOptions extends AXValidationRuleOptions {
  country?: string;
}

declare module '@acorex/core/validation' {
  interface AXValidationRuleOptionsMap {
    nationalId: AXNationalIdRuleOptions;
  }
}

@Injectable()
export class AXNationalIdValidationRule implements AXValidationRule {
  get name() {
    return 'nationalId';
  }

  async validate(value: string, options?: AXNationalIdRuleOptions): Promise<AXValidationRuleResult> {
    const isValid = /^\d{10}$/.test(value ?? '');
    return {
      rule: this.name,
      result: isValid,
      message: isValid ? null : (options?.message ?? 'Invalid national ID'),
      value,
    };
  }
}

import { importProvidersFrom } from '@angular/core';
import { AXValidationModule } from '@acorex/core/validation';
import { AXNationalIdValidationRule } from './national-id.rule';

export const appConfig = {
  providers: [
    importProvidersFrom(
      AXValidationModule.forRoot({
        rules: [AXNationalIdValidationRule],
      }),
    ),
  ],
};

