import { inject } from '@angular/core';
import { AXValidationService } from '@acorex/core/validation';

async function validateField(value: string) {
  const validation = inject(AXValidationService);
  const result = await validation.validate('required', value, { title: 'Email' });

  // Single rule result
  console.log(result.rule);    // 'required'
  console.log(result.result);  // true | false
  console.log(result.message); // null when valid
  console.log(result.value);   // original value

  // Chain summary
  const summary = await validation.ruleFor(value)
    .addRule('required')
    .addRule('email')
    .validate();

  console.log(summary.result);           // false if any rule failed
  console.log(summary.rules.length);     // all rule results collected
  const errors = summary.rules.filter(r => !r.result);
}
